# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = "{#-\n  Silver-Context: Movimentação Paciente\n  Join: atend_paciente_unidade + atendimento_paciente (contexto).\n  Grão: 1 linha por passagem em unidade assistencial.\n  PK: nr_seq_interno.\n  Tratamento de nulos: mesmos macros da camada silver.\n-#}\n\n\nWITH unidade AS (\n  SELECT * FROM glue_catalog.silver.silver_tasy_atend_paciente_unidade\n)\n, atend AS (\n  SELECT * FROM glue_catalog.silver.silver_tasy_atendimento_paciente\n)\nSELECT\n    unidade.nr_seq_interno AS nr_seq_interno\n  , COALESCE(unidade.nr_atendimento, CAST(-1 AS BIGINT)) AS nr_atendimento\n  , COALESCE(unidade.nr_sequencia, CAST(-1 AS BIGINT)) AS nr_sequencia\n  , COALESCE(unidade.cd_setor_atendimento, CAST(-1 AS BIGINT)) AS cd_setor_atendimento\n  , COALESCE(unidade.cd_unidade_basica, CAST(-1 AS BIGINT)) AS cd_unidade_basica\n  , COALESCE(unidade.cd_unidade_compl, CAST(-1 AS BIGINT)) AS cd_unidade_compl\n  , CASE\n  WHEN unidade.dh_entrada_unidade IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_entrada_unidade AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_entrada_unidade AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_entrada_unidade AS TIMESTAMP)\nEND AS dh_entrada_unidade\n  , CASE\n  WHEN unidade.dh_atualizacao IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_atualizacao AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_atualizacao AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_atualizacao AS TIMESTAMP)\nEND AS dh_atualizacao\n  , INITCAP(COALESCE(NULLIF(TRIM(CAST(unidade.nm_usuario AS STRING)), ''), 'indefinido')) AS nm_usuario\n  , COALESCE(unidade.cd_tipo_acomodacao, CAST(-1 AS BIGINT)) AS cd_tipo_acomodacao\n  , CASE\n  WHEN unidade.dh_saida_unidade IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_saida_unidade AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_saida_unidade AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_saida_unidade AS TIMESTAMP)\nEND AS dh_saida_unidade\n  , COALESCE(unidade.nr_atend_dia, CAST(-1 AS BIGINT)) AS nr_atend_dia\n  , INITCAP(COALESCE(NULLIF(TRIM(CAST(unidade.ds_observacao AS STRING)), ''), 'indefinido')) AS ds_observacao\n  , INITCAP(COALESCE(NULLIF(TRIM(CAST(unidade.nm_usuario_original AS STRING)), ''), 'indefinido')) AS nm_usuario_original\n  , CASE\n  WHEN unidade.dh_saida_interno IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_saida_interno AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_saida_interno AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_saida_interno AS TIMESTAMP)\nEND AS dh_saida_interno\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(unidade.ie_passagem_setor AS STRING)), ''), 'i')) AS ie_passagem_setor\n  , COALESCE(unidade.nr_acompanhante, CAST(-1 AS BIGINT)) AS nr_acompanhante\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(unidade.ie_calcular_dif_diaria AS STRING)), ''), 'i')) AS ie_calcular_dif_diaria\n  , COALESCE(unidade.nr_seq_motivo_transf, CAST(-1 AS BIGINT)) AS nr_seq_motivo_transf\n  , CASE\n  WHEN unidade.dh_entrada_real IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_entrada_real AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_entrada_real AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_entrada_real AS TIMESTAMP)\nEND AS dh_entrada_real\n  , INITCAP(COALESCE(NULLIF(TRIM(CAST(unidade.nm_usuario_real AS STRING)), ''), 'indefinido')) AS nm_usuario_real\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(unidade.ie_radiacao AS STRING)), ''), 'i')) AS ie_radiacao\n  , COALESCE(unidade.nr_seq_motivo_dif, CAST(-1 AS BIGINT)) AS nr_seq_motivo_dif\n  , COALESCE(unidade.nr_seq_mot_dif_diaria, CAST(-1 AS BIGINT)) AS nr_seq_mot_dif_diaria\n  , COALESCE(unidade.cd_unidade_externa, CAST(-1 AS BIGINT)) AS cd_unidade_externa\n  , CASE\n  WHEN unidade.dh_alta_medico_setor IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_alta_medico_setor AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_alta_medico_setor AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_alta_medico_setor AS TIMESTAMP)\nEND AS dh_alta_medico_setor\n  , COALESCE(unidade.cd_motivo_alta_setor, CAST(-1 AS BIGINT)) AS cd_motivo_alta_setor\n  , COALESCE(unidade.cd_procedencia_setor, CAST(-1 AS BIGINT)) AS cd_procedencia_setor\n  , COALESCE(unidade.nr_seq_motivo_int, CAST(-1 AS BIGINT)) AS nr_seq_motivo_int\n  , COALESCE(unidade.nr_seq_motivo_int_sub, CAST(-1 AS BIGINT)) AS nr_seq_motivo_int_sub\n  , COALESCE(unidade.nr_seq_motivo_perm, CAST(-1 AS BIGINT)) AS nr_seq_motivo_perm\n  , CASE\n  WHEN unidade.dh_atualizacao_nrec IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_atualizacao_nrec AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_atualizacao_nrec AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_atualizacao_nrec AS TIMESTAMP)\nEND AS dh_atualizacao_nrec\n  , INITCAP(COALESCE(NULLIF(TRIM(CAST(unidade.nm_usuario_nrec AS STRING)), ''), 'indefinido')) AS nm_usuario_nrec\n  , COALESCE(unidade.nr_cirurgia, CAST(-1 AS BIGINT)) AS nr_cirurgia\n  , COALESCE(unidade.nr_seq_pepo, CAST(-1 AS BIGINT)) AS nr_seq_pepo\n  , COALESCE(unidade.nr_seq_agrupamento, CAST(-1 AS BIGINT)) AS nr_seq_agrupamento\n  , COALESCE(\n  ROUND(CAST(unidade.qt_tempo_prev AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS qt_tempo_prev\n  , COALESCE(unidade.nr_seq_unid_ant, CAST(-1 AS BIGINT)) AS nr_seq_unid_ant\n  , CASE\n  WHEN unidade.dh_saida_temporaria IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_saida_temporaria AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_saida_temporaria AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_saida_temporaria AS TIMESTAMP)\nEND AS dh_saida_temporaria\n  , CASE\n  WHEN unidade.dh_retorno_saida_temporaria IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_retorno_saida_temporaria AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_retorno_saida_temporaria AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_retorno_saida_temporaria AS TIMESTAMP)\nEND AS dh_retorno_saida_temporaria\n  , COALESCE(NULLIF(TRIM(CAST(unidade.id_leito_temp_cross AS STRING)), ''), 'ind') AS id_leito_temp_cross\n  , COALESCE(unidade.cd_departamento, CAST(-1 AS BIGINT)) AS cd_departamento\n  , COALESCE(unidade.cd_procedencia_atend, CAST(-1 AS BIGINT)) AS cd_procedencia_atend\n  , COALESCE(unidade.nr_seq_classif_esp, CAST(-1 AS BIGINT)) AS nr_seq_classif_esp\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(unidade.ie_anzics_generated AS STRING)), ''), 'i')) AS ie_anzics_generated\n  , COALESCE(unidade.cd_evolucao, CAST(-1 AS BIGINT)) AS cd_evolucao\n  , CASE\n  WHEN unidade.dh_est_return IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN TRY_CAST(unidade.dh_est_return AS TIMESTAMP) IS NULL THEN TIMESTAMP '1900-01-01 00:00:00'\n  WHEN YEAR(TRY_CAST(unidade.dh_est_return AS TIMESTAMP)) >= 2900 THEN TIMESTAMP '1900-01-01 00:00:00'\n  ELSE TRY_CAST(unidade.dh_est_return AS TIMESTAMP)\nEND AS dh_est_return\n  , COALESCE(atend.cd_pessoa_fisica, CAST(-1 AS BIGINT)) AS atend_cd_pessoa_fisica\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(atend.ie_tipo_atendimento AS STRING)), ''), 'i')) AS atend_ie_tipo_atendimento\n  , CASE\n  WHEN atend.dt_entrada IS NULL THEN DATE '1900-01-01'\n  WHEN TRY_CAST(atend.dt_entrada AS DATE) IS NULL THEN DATE '1900-01-01'\n  WHEN YEAR(TRY_CAST(atend.dt_entrada AS DATE)) >= 2900 THEN DATE '1900-01-01'\n  ELSE TRY_CAST(atend.dt_entrada AS DATE)\nEND AS atend_dt_entrada\n  , CASE\n  WHEN atend.dt_alta IS NULL THEN DATE '1900-01-01'\n  WHEN TRY_CAST(atend.dt_alta AS DATE) IS NULL THEN DATE '1900-01-01'\n  WHEN YEAR(TRY_CAST(atend.dt_alta AS DATE)) >= 2900 THEN DATE '1900-01-01'\n  ELSE TRY_CAST(atend.dt_alta AS DATE)\nEND AS atend_dt_alta\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(atend.ie_status_atendimento AS STRING)), ''), 'i')) AS atend_ie_status_atendimento\n  , COALESCE(atend.cd_medico_resp, CAST(-1 AS BIGINT)) AS atend_cd_medico_resp\n  , LOWER(COALESCE(NULLIF(TRIM(CAST(atend.ie_clinica AS STRING)), ''), 'i')) AS atend_ie_clinica\n  , COALESCE(atend.cd_estabelecimento, CAST(-1 AS BIGINT)) AS atend_cd_estabelecimento\n  , COALESCE(atend.cd_procedencia, CAST(-1 AS BIGINT)) AS atend_cd_procedencia\n  , COALESCE(atend.cd_motivo_alta, CAST(-1 AS BIGINT)) AS atend_cd_motivo_alta\n  \n    , from_utc_timestamp(current_timestamp(), 'America/Sao_Paulo') AS _context_processed_at\n    , CAST(uuid() AS STRING) AS _dbt_invocation_id\n\nFROM unidade\nLEFT JOIN atend\n  ON unidade.nr_atendimento = atend.nr_atendimento\n"
